     1→#' @keywords internal
     2→#' @import assertthat
     3→prep_constraints <- function(X, A, M, tol = 1e-8, remedy = c("error", "ridge", "clip", "identity"), verbose = FALSE) {
     4→  n <- nrow(X)
     5→  p <- ncol(X)
     6→  
     7→  remedy <- match.arg(remedy)
     8→  
     9→  # --- Process A (Column constraints) ---
    10→  if (is.null(A)) {
    11→    A <- Matrix::sparseMatrix(i=1:p, j=1:p, x=1.0, dims=c(p,p))
    12→  } else if (is.vector(A)) {
    13→    assert_that(length(A) == p, msg="Length of vector A must equal ncol(X)")
    14→    assert_that(all(A >= -tol), msg="Diagonal elements of A (from vector) must be non-negative.")
    15→    A <- Matrix::Diagonal(n=p, x=A)
    16→  } else {
    17→    # Ensure it's a Matrix object first for isSymmetric etc.
    18→    if (!is(A, "Matrix")) { A <- Matrix::Matrix(A, sparse=TRUE) }
    19→    assert_that(nrow(A) == p, msg=paste("nrow(A) != ncol(X) -- ", nrow(A), " != ", p))
    20→    assert_that(ncol(A) == p, msg=paste("ncol(A) != ncol(X) -- ", ncol(A), " != ", p))
    21→    if (!Matrix::isSymmetric(A)) {
    22→        warning("Matrix A is not symmetric, taking the upper triangle.")
    23→        A <- Matrix::forceSymmetric(A, uplo="U")
    24→    }
    25→    # Ensure sparse format (forceSymmetric might return dsyMatrix)
    26→    if (!is(A, "sparseMatrix")) { A <- as(A, "sparseMatrix") }
    27→    # Check PSD (only eigenvalues for efficiency)
    28→    min_eig_A <- tryCatch(RSpectra::eigs_sym(A, k=1, which="SA")$values,
    29→                          error=function(e) {NA}) # Handle potential errors
    30→    if (is.na(min_eig_A) || min_eig_A < -tol) {
    31→        if (verbose) message("Matrix A is not PSD (min eig: ", signif(min_eig_A, 4), "). Applying remedy: ", remedy)
    32→        if (remedy == "error") {
    33→            stop("Matrix A must be positive semi-definite (smallest eigenvalue >= -tol). Error was: ", min_eig_A)
    34→        } else if (remedy == "ridge") {
    35→            ridge_val <- tol - min_eig_A # Amount to add to diagonal
    36→            A <- A + Matrix::Diagonal(p, x = ridge_val)
    37→            A <- (A + Matrix::t(A)) / 2 # Re-symmetrize
    38→        } else if (remedy == "clip") {
    39→            A_dense <- as.matrix((A + Matrix::t(A))/2) # Ensure symmetry for eigen
    40→            E <- eigen(A_dense, symmetric = TRUE)
    41→            vals_clipped <- pmax(E$values, tol) # Clip negative eigenvalues
    42→            A <- Matrix::Matrix(E$vectors %*% Matrix::diag(vals_clipped) %*% Matrix::t(E$vectors), sparse=TRUE)
    43→            A <- (A + Matrix::t(A)) / 2 # Re-symmetrize after reconstruction
    44→        } else if (remedy == "identity") {
    45→            A <- Matrix::Diagonal(p)
    46→        }
    47→    }
    48→  }
    49→  
    50→  # --- Process M (Row constraints) ---
    51→  if (is.null(M)) {
    52→    M <- Matrix::sparseMatrix(i=1:n, j=1:n, x=1.0, dims=c(n,n))
    53→  } else if (is.vector(M)) {
    54→    assert_that(length(M) == n, msg="Length of vector M must equal nrow(X)")
    55→    assert_that(all(M >= -tol), msg="Diagonal elements of M (from vector) must be non-negative.")
    56→    M <- Matrix::Diagonal(n=n, x=M)
    57→  } else {
    58→    if (!is(M, "Matrix")) { M <- Matrix::Matrix(M, sparse=TRUE) }
    59→    assert_that(nrow(M) == n, msg=paste("nrow(M) != nrow(X) -- ", nrow(M), " != ", n))
    60→    assert_that(ncol(M) == n, msg=paste("ncol(M) != nrow(X) -- ", ncol(M), " != ", n))
    61→    if (!Matrix::isSymmetric(M)) {
    62→        warning("Matrix M is not symmetric, taking the upper triangle.")
    63→        M <- Matrix::forceSymmetric(M, uplo="U")
    64→    }
    65→    if (!is(M, "sparseMatrix")) { M <- as(M, "sparseMatrix") }
    66→    # Check PSD
    67→    min_eig_M <- tryCatch(RSpectra::eigs_sym(M, k=1, which="SA")$values,
    68→                          error=function(e) {NA})
    69→    if (is.na(min_eig_M) || min_eig_M < -tol) {
    70→        if (verbose) message("Matrix M is not PSD (min eig: ", signif(min_eig_M, 4), "). Applying remedy: ", remedy)
    71→        if (remedy == "error") {
    72→            stop("Matrix M must be positive semi-definite (smallest eigenvalue >= -tol). Error was: ", min_eig_M)
    73→        } else if (remedy == "ridge") {
    74→            ridge_val <- tol - min_eig_M
    75→            M <- M + Matrix::Diagonal(n, x = ridge_val)
    76→            M <- (M + Matrix::t(M)) / 2
    77→        } else if (remedy == "clip") {
    78→            M_dense <- as.matrix((M + Matrix::t(M))/2)
    79→            E <- eigen(M_dense, symmetric = TRUE)
    80→            vals_clipped <- pmax(E$values, tol)
    81→            M <- Matrix::Matrix(E$vectors %*% Matrix::diag(vals_clipped) %*% Matrix::t(E$vectors), sparse=TRUE)
    82→            M <- (M + Matrix::t(M)) / 2
    83→        } else if (remedy == "identity") {
    84→            M <- Matrix::Diagonal(n)
    85→        }
    86→    }
    87→  }
    88→  
    89→  # Ensure consistent sparse format (dgCMatrix is common)
    90→  list(A = as(A, "dgCMatrix"), M = as(M, "dgCMatrix"))
    91→}
